function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const teleportMap: number[][][] = [];
    for (let i = 0; i < m; i++) {
        teleportMap[i] = [];
        for (let j = 0; j < n; j++) {
            const currentVal = grid[i][j];
            const list: number[][] = [];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= currentVal) {
                        list.push([x, y]);
                    }
                }
            }
            teleportMap[i][j] = list;
        }
    }

    const dist = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(k + 1).fill(Infinity)));
    dist[0][0][0] = 0;

    class PriorityQueue {
        private heap: [number, number, number, number][];
        constructor() {
            this.heap = [];
        }
        enqueue(cost: number, i: number, j: number, t: number) {
            const node = [cost, i, j, t];
            this.heap.push(node);
            this.heapifyUp(this.heap.length - 1);
        }
        dequeue(): [number, number, number, number] | null {
            if (this.heap.length === 0) return null;
            const node = this.heap[0];
            this.heap[0] = this.heap[this.heap.length - 1];
            this.heap.pop();
            this.heapifyDown(0);
            return node;
        }
        heapifyUp(index: number) {
            let parent = Math.floor((index - 1) / 2);
            while (index > 0 && this.heap[index][0] < this.heap[parent][0]) {
                [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]];
                index = parent;
                parent = Math.floor((index - 1) / 2);
            }
        }
        heapifyDown(index: number) {
            let smallest = index;
            const left = 2 * index + 1;
            const right = 2 * index + 2;
            if (left < this.heap.length && this.heap[left][0] < this.heap[smallest][0]) {
                smallest = left;
            }
            if (right < this.heap.length && this.heap[right][0] < this.heap[smallest][0]) {
                smallest = right;
            }
            if (smallest !== index) {
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                this.heapifyDown(smallest);
            }
        }
        isEmpty(): boolean {
            return this.heap.length === 0;
        }
    }

    const pq = new PriorityQueue();
    pq.enqueue(0, 0, 0, 0);

    while (!pq.isEmpty()) {
        const [cost, i, j, t] = pq.dequeue();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dist[i][j][t]) {
            continue;
        }

        const directions = [[0, 1], [1, 0]];
        for (const [dx, dy] of directions) {
            const ni = i + dx;
            const nj = j + dy;
            if (ni < m && nj < n) {
                const newCost = cost + grid[ni][nj];
                if (newCost < dist[ni][nj][t]) {
                    dist[ni][nj][t] = newCost;
                    pq.enqueue(newCost, ni, nj, t);
                }
            }
        }

        if (t < k) {
            for (const [x, y] of teleportMap[i][j]) {
                const newCost = cost;
                if (newCost < dist[x][y][t + 1]) {
                    dist[x][y][t + 1] = newCost;
                    pq.enqueue(newCost, x, y, t + 1);
                }
            }
        }
    }

    return dist[m - 1][n - 1][k];
}

