    // Preprocess teleport_map
    const m = grid.length;
    const n = grid[0].length;
    const teleport_map: (number[][])[] = [];
    for (let i = 0; i < m; i++) {
        teleport_map[i] = [];
        for (let j = 0; j < n; j++) {
            const current_val = grid[i][j];
            const list: number[][] = [];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= current_val) {
                        list.push([x, y]);
                    }
                }
            }
            teleport_map[i][j] = list;
        }
    }

    // Dijkstra's algorithm
    const dist = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(k+1).fill(Infinity)));
    dist[0][0][0] = 0;

    // Priority queue: [cost, i, j, t]
